import{_ as e,o as t,c as s,S as n}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"Prompt Engineering（提示词工程）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_22-prompt_engineering.md","filePath":"直击概念/17ai/s_ai_22-prompt_engineering.md","lastUpdated":1778207238000}'),i={name:"直击概念/17ai/s_ai_22-prompt_engineering.md"};function r(l,a,p,o,d,h){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="prompt-engineering-提示词工程" tabindex="-1">Prompt Engineering（提示词工程） <a class="header-anchor" href="#prompt-engineering-提示词工程" aria-label="Permalink to &quot;Prompt Engineering（提示词工程）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>Prompt Engineering 是设计和优化与 LLM 交互的<strong>输入文本</strong>，以引导模型生成期望输出的技术。它是目前<strong>不需要模型训练/微调</strong>即可影响模型行为的最重要手段。</p><p>对前端开发者而言，Prompt Engineering 是构建 AI 功能的核心技能——你写出的 prompt 质量直接决定了用户体验的 AI 功能效果。</p><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><h3 id="清晰明确" tabindex="-1">清晰明确 <a class="header-anchor" href="#清晰明确" aria-label="Permalink to &quot;清晰明确&quot;">​</a></h3><ul><li>说清楚你想要什么，而不是&quot;做得更好&quot;</li><li>指定输出格式（JSON、Markdown、纯文本）</li></ul><h3 id="提供上下文" tabindex="-1">提供上下文 <a class="header-anchor" href="#提供上下文" aria-label="Permalink to &quot;提供上下文&quot;">​</a></h3><ul><li>给模型设定角色（&quot;你是一位资深前端面试官...&quot;）</li><li>提供背景信息、示例数据</li></ul><h3 id="分步引导" tabindex="-1">分步引导 <a class="header-anchor" href="#分步引导" aria-label="Permalink to &quot;分步引导&quot;">​</a></h3><ul><li>复杂任务拆分为子步骤</li><li>明确每一步的输入和期望输出</li></ul><h2 id="关键技巧" tabindex="-1">关键技巧 <a class="header-anchor" href="#关键技巧" aria-label="Permalink to &quot;关键技巧&quot;">​</a></h2><h3 id="zero-shot-prompting" tabindex="-1">Zero-shot Prompting <a class="header-anchor" href="#zero-shot-prompting" aria-label="Permalink to &quot;Zero-shot Prompting&quot;">​</a></h3><p>不给示例，直接提问：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;用 JavaScript 实现一个节流函数&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="few-shot-prompting" tabindex="-1">Few-shot Prompting <a class="header-anchor" href="#few-shot-prompting" aria-label="Permalink to &quot;Few-shot Prompting&quot;">​</a></h3><p>给几个输入-输出示例，模型学习模式后完成新任务：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;英文单词：dog → 中文：狗</span></span>
<span class="line"><span>英文单词：cat → 中文：猫</span></span>
<span class="line"><span>英文单词：bird →&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="chain-of-thought-cot-思维链" tabindex="-1">Chain-of-Thought（CoT / 思维链） <a class="header-anchor" href="#chain-of-thought-cot-思维链" aria-label="Permalink to &quot;Chain-of-Thought（CoT / 思维链）&quot;">​</a></h3><p>要求模型<strong>逐步推理</strong>而不是直接给答案：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;问题：小明有 5 个苹果，吃了 2 个，又买了 3 个，现在有几个？</span></span>
<span class="line"><span>让我们一步步思考：</span></span>
<span class="line"><span>1. 小明最初有 5 个苹果</span></span>
<span class="line"><span>2. 吃了 2 个，剩下 5-2=3 个</span></span>
<span class="line"><span>3. 又买了 3 个，现在有 3+3=6 个</span></span>
<span class="line"><span>答案：6 个&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>关键</strong>：只需在 prompt 中添加&quot;Let&#39;s think step by step&quot;即可激活 CoT 能力。</p><h3 id="system-prompt-系统提示" tabindex="-1">System Prompt（系统提示） <a class="header-anchor" href="#system-prompt-系统提示" aria-label="Permalink to &quot;System Prompt（系统提示）&quot;">​</a></h3><p>在对话开始前设置全局指令，定义模型的角色、行为边界和输出风格：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;你是一位精通 TypeScript 的前端工程师。回答问题时：</span></span>
<span class="line"><span>- 代码示例使用 TypeScript</span></span>
<span class="line"><span>- 解释要简洁专业</span></span>
<span class="line"><span>- 不确定的地方要明确标注&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="role-prompting" tabindex="-1">Role Prompting <a class="header-anchor" href="#role-prompting" aria-label="Permalink to &quot;Role Prompting&quot;">​</a></h3><p>给模型一个具体的&quot;人设&quot;：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;你现在是一位有 10 年经验的 Vue.js 架构师，请评估这段代码...&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="structured-output" tabindex="-1">Structured Output <a class="header-anchor" href="#structured-output" aria-label="Permalink to &quot;Structured Output&quot;">​</a></h3><p>要求模型输出特定格式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;请以 JSON 格式输出，包含以下字段：question, answer, difficulty&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="常见-prompt-模式" tabindex="-1">常见 Prompt 模式 <a class="header-anchor" href="#常见-prompt-模式" aria-label="Permalink to &quot;常见 Prompt 模式&quot;">​</a></h2><table><thead><tr><th>模式</th><th>描述</th><th>示例</th></tr></thead><tbody><tr><td>指令式</td><td>直接给任务</td><td>&quot;翻译成英文&quot;</td></tr><tr><td>角色式</td><td>赋予人设</td><td>&quot;作为资深律师...&quot;</td></tr><tr><td>示例式</td><td>Few-shot</td><td>给 3 个例子后提问</td></tr><tr><td>格式约束</td><td>指定输出格式</td><td>&quot;以 JSON 格式返回&quot;</td></tr><tr><td>思维链</td><td>要求推理过程</td><td>&quot;一步步思考&quot;</td></tr><tr><td>自我批评</td><td>要求自查</td><td>&quot;检查你的回答是否有错误&quot;</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>什么是 Prompt Engineering？为什么它比微调更常用？</li><li>Zero-shot 和 Few-shot 的区别？各举一个使用场景。</li><li>你做过哪些 Prompt Engineering 的实践？效果如何？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI Prompt Engineering Guide</a></li><li><a href="https://docs.anthropic.com/claude/prompt-library" target="_blank" rel="noreferrer">Anthropic Prompt Library</a></li><li><a href="https://www.promptingguide.ai/" target="_blank" rel="noreferrer">Prompt Engineering Guide - DAIR.AI</a></li></ul>`,37)])])}const b=e(i,[["render",r]]);export{c as __pageData,b as default};
